respuesta_modelo:
[
  {
    "tool": "notify",
    "args": {
      "customer_id": "$1.id",
      "message": "Ana Torres, your invoice is now ready."
    }
  },
  {
    "tool": "get_invoice",
    "args": {
      "customer_id": "$1.id"
    }
  }
]

[
  {
    "tool": "get_invoice",
    "args": {
      "customer_id": "$1.id"
    }
  },
  {
    "tool": "notify",
    "args": {
      "customer_id": "$1.id",
      "message": "Your invoice INV-33 has been canceled and a refund is being processed."
    }
  }
]

[
  {
    "tool": "get_account",
    "args": {
      "customer_id": "C-30"
    }
  },
  {
    "tool": "notify",
    "args": {
      "customer_id": "$1.id",
      "message": "Renewal reminder: Your account is inactive. Please renew to maintain service."
    }
  },
  {
    "tool": "open_ticket",
    "args": {
      "customer_id": "$1.id",
      "severity": "medium",
      "description": "Account is inactive and not renewed."
    }
  }
]

{
  "setup": [
    {
      "tool": "find_customer",
      "args": {
        "name": "Grace Chen"
      }
    },
    {
      "tool": "get_account",
      "args": {
        "customer_id": "$1.id"
      }
    },
    {
      "tool": "get_balance",
      "args": {
        "account_id": "$2.account_id"
      }
    }
  ],
  "branches": [
    {
      "condition": {
        "field": "$1.balance",
        "op": ">=",
        "value": 5000
      },
      "calls": [
        {
          "tool": "notify",
          "args": {
            "customer_id": "$1.id",
            "message": "You are eligible for the premium plan!"
          }
        }
      ]
    },
    {
      "condition": "else",
      "calls": [
        {
          "tool": "notify",
          "args": {
            "customer_id": "$1.id",
            "message": "You are on the standard plan."
          }
        }
      ]
    }
  ]
}
